function LMapBase:Destroy()
	self:OnDestroy()
	self:ClearMapThemeShow()
	local mapTimer = self._mapTimer
	if (mapTimer) then
		mapTimer:Destroy()
		self._mapTimer = nil
	end

	if self._behaviour then
		self._behaviour:Dispose()
		self._behaviour = nil
	end

	self:ClearTempEvent()

	if CS.IsValidObject(self._mapTrans) then
		self:DestroyMapTrans(self._bundleName)
	end

	if self._resRequester then
		self._resRequester:Dispose()
		self._resRequester = nil
	end

	if self._themeResRequester then
		self._themeResRequester:Dispose()
		self._themeResRequester = nil
	end

	LxNodeBase.Dispose(self)

	self._isDestroy = true
end

function LMapBase:IsDestroy()
