function LMapBase:Create(parentScene, parentTrans)
	self._parentScene = parentScene
	self._parentTrans = parentTrans
	self:SetMapClassName(self:GetClassName())

	self._mapTimer = LxTimer:New()

	self:MapEventRecv(EventNames.ON_RED_POINT_CHANGE, function(...)
		self:RefreshRedPoint(...)
		self:OnTryRefreshRedPoint(...)
	end)
	--gModelRedPoint:MapStatusInit() --不需要手动刷新红点
	self:OnCreate()
end

function LMapBase:ResetMap(argList)
