end

function LMapBase:ResetCameraPos(time, cameraPos)
	if self._mapCameraCom then
		local scene = self._parentScene
		local pos = scene:GetSceneCameraInitPosition() or Vector3(0, 0, 0)
		local offset = scene:GetCameraAdaptOffset() + self._mapOffset
		local mapPos = Vector3(pos.x, pos.y + offset, pos.z)
		time = time or 0
		cameraPos = cameraPos or mapPos
		self._mapCameraCom:SetCameraPos(cameraPos, time)
	end
end

function LMapBase:ResetBgPos(y)
	self:SetBgOffset(y)
end

function LMapBase:GetDefaultCameraPos()
	local scene = self._parentScene
	local pos = scene:GetSceneCameraInitPosition() or Vector3(0, 0, 0)
	local offset = scene:GetCameraAdaptOffset()
	return Vector3(pos.x, pos.y + offset, pos.z)
end

function LMapBase:InitCameraComponent()
	local layerRoot = CS.FindTrans(self._mapTrans, "LayerRoot")
	local comp = layerRoot:GetComponent(typeofYXIMapCamera)
	if not comp then
		comp = layerRoot.gameObject:AddComponent(typeofYXIMapCamera)
	end
	self._mapCameraCom = comp

	self._bgTrans = CS.FindTrans(layerRoot, "LayerBg/Bg")
	if self._bgTrans then
		self._bgInitPos = self._bgTrans.position
	end
end

function LMapBase:GetMapCameraCom()
	return self._mapCameraCom
end

function LMapBase:OnCameraAdapt()
	self:ResetCameraPos()
end

function LMapBase:SetMapOffset(offset)
	self._mapOffset = offset
end

function LMapBase:SetBgOffset(offset)
	self._bgOffset = offset
	self:ReSetBgPosY()
end

function LMapBase:ReSetBgPosY()
	if not self:IsMapReady() then
		return
	end
	if self._bgInitPos then
		if self._bgOffset then
			self._bgTrans.position = Vector3(self._bgInitPos.x, self._bgOffset, self._bgInitPos.z)
			self._bgOffset = nil
		else
			self._bgTrans.position = self._bgInitPos
		end
	end
end

---退出当前地图到后台
function LMapBase:ExitMap()
	self._isExited = true
	self:ReSetBgPosY()

	if self:IsCheckClear() then
		self._lastExistTime = GetTimestamp()
	end
	local mapName = self:GetMapName()
	self:OnExitMap()

	self:RemoveAllTimer()
	self:ClearTempEvent()
	FireEvent(EventNames.ON_MAP_EXIT, mapName)
	self:ReleaseRedPointFunc()
end

function LMapBase:Shake(time, intensityX, intensityY)
	if self._mapCameraCom then
		self._mapCameraCom:StartShake(time, intensityX, intensityY, 0)
	end
end

