function LMapBase:StartLoadMap(readyCall, prefabName)
	self._readyCall = readyCall
	local curMapName = self:GetMapName()
	if string.isempty(prefabName) then
		prefabName = self:GetMapThemePrefab()
	end
	if string.isempty(prefabName) then
		prefabName = curMapName
	end
	if (string.isempty(curMapName)) then
		LogError("not setting map name in map class " .. self:GetClassName())
		return
	end
	if self._bLoading and self._mapPrefabName == prefabName then
		return
	end

	self._bLoading = true

	self._isMapReady = false
	self._mapPrefabName = prefabName

	if self._resRequester then
		self._resRequester:Dispose()
		self._resRequester = nil
	end
	local assetPath = string.format("Map/Prefabs/%s.prefab", prefabName)
	self._resRequester = LxResUtil.GetAssetRequester(assetPath, typeofGameObject, function(obj)
		self:OnMapLoaded(curMapName, obj, prefabName)
	end)
	self._resRequester:StartRequester()
end


function LMapBase:OnMapLoaded(curMapName, asset, assetName, bundleName)
	if self:IsDestroy() then return end

	local parentTrans = self._parentTrans
	if not parentTrans or not CS.IsValidObject(parentTrans) then return end

	if curMapName ~= self._mapName then return end

	self._bLoading = false

	if not asset then
		LogError("error load map, asset not exist | name=" ..
		tostring(assetName) .. "  | classname=" .. tostring(self:GetMapClassName()))
		return
	end

	--local instGo = LxResUtil.NewObject(asset, bundleName)
	local instGo = LxResUtil.NewObject(asset)
	instGo.name = curMapName
	local instTrans = instGo.transform
	instTrans:SetParent(parentTrans, false)
	--CS.ShowObject(instTrans,false)

	self:DestroyMapTrans(self._bundleName)
	self._bundleName = bundleName
	self._showMapName = curMapName
	self._mapTrans = instTrans
	--if self._bVisible then
	--	CS.ShowObject(instTrans,self._bVisible)
	--end


	self:InitCameraComponent()
	self:ReSetBgPosY()
	local mapCityTheme = gLGameDisplayTheme:GetMapTheme()
	self:InitMapThemeShow(mapCityTheme)
	self:InitMapLanguage()

	self:OnPrepareEnterMap()

	if not self._bVisible then self:UpdateMapVisible() end

	self:OnMapReady()
end

function LMapBase:InitMapLanguage()
	local langNodes = gLGameLanguage:GetWndLanguageNodes(self._showMapName)
	if not langNodes then
		return
	end

	local langTag = gLGameLanguage:GetLanguageFlag()
	local langNodeTrans = nil
	local langNodeSprite = nil
	local langResName = nil
	for idx, mapNodeItem in ipairs(langNodes) do
		langNodeTrans = self._mapTrans:Find(mapNodeItem.uiPath)
		langNodeSprite = LxUiHelper.FindSceneSprite(langNodeTrans)
		if langNodeSprite and CS.IsValidObject(langNodeSprite.sprite) then
			langResName = gLGameLanguage:GetResName(langNodeSprite.sprite.name)
			if not string.isempty(langResName) then
				self:SetSpriteRenderer(langNodeTrans, langResName)

			end
		end
	end
end

function LMapBase:AutoInitLanguage(rootTrans)
	if CS.IsNullObject(rootTrans) then
		return
	end

	local spriteNode = nil
	local spriteResName = nil
	local langResName = nil
	local isNativeSize = nil
	local spriteNodes = rootTrans:GetComponentsInChildren(typeSpriteRenderer, true)
	local nodeLen = spriteNodes.Length

	for k = 1, nodeLen do
		spriteNode = spriteNodes[k - 1]
		if spriteNode and CS.IsValidObject(spriteNode.sprite) then
			spriteResName = spriteNode.sprite.name
			langResName, isNativeSize = gLGameLanguage:GetResName(spriteResName)
			if spriteResName ~= langResName then
				self:SetSpriteRenderer(spriteNode, langResName)
			end
		end
	end
end

function LMapBase:DestroyMapTrans(bundleName)
	local oldMapTrans = self._mapTrans
	if oldMapTrans then
		LxResUtil.DestroyObject(oldMapTrans.gameObject)

		self:OnDestroyMapTran()
	end
	self._mapTrans = nil
end

