function LMapBase:EnterMap()
	self:ResetCameraPos()
	LXFW.LxLog.GAME(string.format("%s (%s) OnEnterMap ", self:GetClassName(), self:GetMapName()))

	--if LOG_INFO_ENABLED then
	--	print(string.format("%s (%s) OnEnterMap ", self:GetClassName(), self:GetMapName()))
	--end

	self._effectKeyList = {}

	self._isGuideReady = not self._delayGuideReady

	if self:TryChangeMapTheme() then
		return
	end

	self:OnEnterMap()

	if not self._delayGuideReady then
		local mapName = self:GetMapName()
		--self._isGuideReady = true
		FireEvent(EventNames.ON_MAP_FINISH, mapName)
	end

	--FireEvent(EventNames.ON_CLICK_MAIN_BTN)
	self:PlayMapMusic()

	self:RegisterRedPoint()
end

