function LMapBase:SetMapVisible(bVisible)
	if self._bVisible == bVisible then
		return
	end
	self._bVisible = bVisible
	self:UpdateMapVisible()
end

function LMapBase:UpdateMapVisible()
	if (not self:IsMapValid()) then return end
	local bVisible = self._bVisible

	if self._mapCameraCom and CS.IsValidObject(self._mapCameraCom) then
		self._mapCameraCom.enabled = bVisible
	end

	if bVisible then
		self._mapTrans.position = Vector3(0, 0, 0)
		self._mapTrans:SetAsLastSibling()
	else
		self._mapTrans.position = Vector3(10000, 10000, 10000)
	end

	--CS.ShowObject(self._mapTrans, self._bVisible)
	if self._bVisible then
		self._mapTrans:SetAsLastSibling()
	end

	--if self._bVisible then
	--	self._mapTrans.position = Vector3(0,0,0)
	--else
	--	self._mapTrans.position = Vector3(10000,10000,10000)
	--end
end

