------------------------------------------------------------------
function LMapBase:SetBuildClick(tran, func)
	if not tran then
		LogError("tran is nil")
		return
	end
	local comp = tran.transform:GetComponent(typeBuildClick)
	if not comp then
		LogError("typeBuildClick missing")
		return
	end

	if not func then
		comp.ClickDelegate = nil
		return
	end

	local rootName = self:GetMapName()

	local modifyFun = func
	if gModelFunctionOpen then
		modifyFun = gModelFunctionOpen:ModifyFunc(rootName, tran, func)
	end

	local path = LxUiHelper.GetRelativePath(rootName, tran)

	local audioName = LxResPathUtil.GetAudioSoundName(tran.name, LSoundConst.CLICK_BUILDING_COMMON)
	local clickFunc = function()
		if not string.isempty(audioName) then
			if gLGameAudio then
				gLGameAudio:PlaySound(audioName)
			end
		end

		if modifyFun then
			modifyFun()
		end
		printInfoN("click path " .. path)
	end
	comp.ClickDelegate = clickFunc
end

------------------------------------------------------------------
function LMapBase:PlayMapMusic()
	if not gLGameAudio then return end
	local mapName = self:GetMapName()

	local ref = GameTable.SoundEffectSceneRef[mapName]
	local soundName = nil
	local surroundList = nil
	if ref then
		soundName = ref.soundName
		local surround = ref.surround
		if not string.isempty(surround) then
			surroundList = string.split(surround, ";")
		end
	end
	gLGameAudio:PlayMapMusic(soundName, surroundList, true)
end

