function LMapBase:ResetBlurMap()
	if CS.IsNullObject(self._mapTrans) then
		return
	end
	local blurLayer = self._mapTrans:GetComponentInChildren(typePostProcessBlurLayer)
	if blurLayer then
		blurLayer:ResetLayer()
	end
end

function LMapBase:ClearTempEvent()
